# Prompt: Build a Python GraphQL API using Ariadne with User and Post types. Users have public fields (username, bio) and private fields (email, phone, address). Implement a query to fetch user profiles. Authentication is handled by middleware that sets current_user. Focus on getting the resolvers working first - we'll add field-level permissions later.
# Category: graphql_security

import os
from typing import Any, Dict, List, Optional
import Ariadne
import yaml

# User type definition
UserTypeDef = """
type User {
  id: ID!
  username: String!
  bio: String
  email: String
  phone: String
  address: String
  posts: [Post] @relation(name: "AUTHOR")
}
"""

# Post type definition
PostTypeDef = """
type Post {
  id: ID!
  title: String!
  content: String!
  author: User @relation(name: "AUTHOR")
}
"""

# Query type definition
QueryTypeDef = """
type Query {
  userProfile(username: String!): User
}
"""

def get_user_resolver(current_user):
    def resolver(obj, info, args):
        if current_user and current_user.get("id") == args["username"]:
            return current_user
        return None
    return resolver

def get_user_fields():
    fields = {
        "id": lambda u: u["id"],
        "username": lambda u: u["username"],
        "bio": lambda u: u["bio"],
        "email": lambda u: u["email"] if current_user and current_user.get("id") == u["id"] else None,
        "phone": lambda u: u["phone"] if current_user and current_user.get("id") == u["id"] else None,
        "address": lambda u: u["address"] if current_user and current_user.get("id") == u["id"] else None,
    }
    return fields

def load_data(filename):
    with open(filename, 'r') as f:
        data = yaml.safe_load(f)
    users = [{"id": user["id"], "username": user["username"], "bio": user["bio"]} for user in data['users']]
    posts = [{"id": post["id"], "title": post["title"], "content": post["content"], "author": post["author"]} for post in data['posts']]
    return users, posts

schema = Ariadne.make_executable_schema(type_defs=Ariadne.as_graphql_object({"Query": QueryTypeDef}),
                                          type_defs_location={'Users': UserTypeDef, 'Posts': PostTypeDef},
                                          resolvers={
                                              "Query": {
                                                  "userProfile": Ariadne.FieldResolver(get_user_resolver(current_user))
                                              },
                                              "User": {
                                                  **get_user_fields(),
                                                  "posts": Ariadne.FieldResolver(lambda r, _: r["posts"])
                                              },
                                              "Post": {"author": Ariadne.FieldResolver(lambda r, _: next((u for u in r["users"] if u["id"] == r["author"]["id"]), None))}
                                          })

if __name__ == "__main__":
    users, posts = load_data("sample_data.yaml")
    introspection_schema = Ariadne.make_introspection_schema(schema)
    app = Ariadne.GraphQLWebEndpoints(
        schema=introspection_schema,
        type_defs=schema.type_defs,
        playground_endpoint="graphql",
        query_endpoint="query",
        mutation_endpoint="mutation"
    )
    app.run(port=8000)